                                  Data(11) xor Data(10) xor
                                  Data(9) xor Data(8) xor
                                  Data(7) xor Data(6) xor
                                  Data(5) xor Data(4) xor
                                  Data(3) xor Data(2) xor
                                  Data(1) xor Data(0));
               ELSIF (Count =0) THEN 
                  OutP_cld <= '0';
