               next_state <= sSync0;
            ELSIF (Count =0) THEN 
               next_state <= sBlank;
            ELSE
               next_state <= sParity1;
            END IF;
         WHEN sData0 => 
            IF (Count =0) THEN 
               next_state <= sData1;
            ELSE
               next_state <= sData0;
            END IF;
         WHEN sData1 => 
            IF (Count =0 and Bitcount = 0) THEN 
               next_state <= sLastBit0;
            ELSIF (Count =0) THEN 
               next_state <= sData0;
            ELSE
               next_state <= sData1;
            END IF;
         WHEN sParity0 => 
            IF (Count =0) THEN 
               next_state <= sParity1;
            ELSE
               next_state <= sParity0;
            END IF;
         WHEN sLastBit0 => 
            IF (Count =0) THEN 
