            ELSE
               next_state <= sLastBit0;
            END IF;
         WHEN sLastBit1 => 
            IF (Count =0) THEN 
               next_state <= sParity0;
            ELSE
               next_state <= sLastBit1;
            END IF;
         WHEN sBlank => 
            IF (tmr_Blank = '1') THEN 
               next_state <= sIdle;
            ELSE
               next_state <= sBlank;
            END IF;
         WHEN OTHERS =>
            next_state <= sIdle;
      END CASE;
